#[test]
fn test_config_document_structure_with_headings() {
    // Tests document structure with DOCX heading-driven nesting
    let path = r#"docx/fake.docx"#;
    let mime_type: Option<String> = None;
    let config_json = serde_json::json!({"include_document_structure": true});
    let config = serde_json::from_value(config_json).unwrap();
    let result = extract_file_sync(path, mime_type.as_deref(), &config).expect("should succeed");
    assert_eq!(
        result.mime_type.trim(),
        r#"application/vnd.openxmlformats-officedocument.wordprocessingml.document"#,
        "equals assertion failed"
    );
    assert!(result.document.is_some(), "expected document to be present");
    assert!(!result.document.as_ref().unwrap().nodes.is_empty(), "expected >= 1");
}

